from __future__ import annotations

import re
from collections import Counter

from relocation_jobs.core.ats_constants import INCLUDE_KEYWORDS
from relocation_jobs.mcp.types import KeywordCoverage, ValidationIssue

_STOPWORDS = frozenset({
    "and", "are", "for", "from", "have", "that", "this", "with", "will", "your",
    "you", "our", "the", "who", "what", "when", "where", "which", "their", "they",
    "them", "been", "being", "about", "into", "through", "during", "before", "after",
    "above", "below", "between", "under", "again", "further", "then", "once", "here",
    "there", "all", "each", "few", "more", "most", "other", "some", "such", "only",
    "own", "same", "than", "too", "very", "can", "just", "don", "should", "now",
    "role", "team", "work", "job", "jobs", "company", "position", "looking", "join",
    "help", "build", "using", "used", "use", "able", "well", "also", "within",
})

_MAX_KEYWORDS = 25
_MIN_KEYWORD_LEN = 3
_DEFAULT_MIN_SCORE = 40


def extract_jd_keywords(jd_text: str, title: str = "") -> list[str]:
    blob = f"{title}\n{jd_text}".lower()
    keywords: list[str] = []
    seen: set[str] = set()

    for phrase in sorted(INCLUDE_KEYWORDS, key=len, reverse=True):
        term = phrase.strip().lower()
        if len(term) < _MIN_KEYWORD_LEN or term in seen:
            continue
        if term in blob:
            keywords.append(term)
            seen.add(term)

    for word in re.findall(r"[a-z0-9+#]+", title.lower()):
        if len(word) >= _MIN_KEYWORD_LEN and word not in _STOPWORDS and word not in seen:
            keywords.append(word)
            seen.add(word)

    words = re.findall(r"[a-z][a-z0-9+#.-]{2,}", jd_text.lower())
    freq = Counter(
        word for word in words
        if word not in _STOPWORDS and len(word) >= 4
    )
    for word, _count in freq.most_common(20):
        if word in seen:
            continue
        keywords.append(word)
        seen.add(word)
        if len(keywords) >= _MAX_KEYWORDS:
            break

    return keywords[:_MAX_KEYWORDS]


def keyword_coverage(tex: str, keywords: list[str]) -> KeywordCoverage:
    if not keywords:
        return KeywordCoverage(score=100, matched=[], missing=[], min_score=_DEFAULT_MIN_SCORE)

    tex_lower = tex.lower()
    matched: list[str] = []
    missing: list[str] = []
    for keyword in keywords:
        if keyword.lower() in tex_lower:
            matched.append(keyword)
        else:
            missing.append(keyword)

    score = int(round(100 * len(matched) / len(keywords)))
    return KeywordCoverage(
        score=score,
        matched=matched,
        missing=missing,
        min_score=_DEFAULT_MIN_SCORE,
    )


def keyword_issues(
    tex: str,
    jd_text: str,
    *,
    title: str = "",
    min_score: int = _DEFAULT_MIN_SCORE,
) -> tuple[list[ValidationIssue], KeywordCoverage | None]:
    jd = (jd_text or "").strip()
    if not jd:
        return [], None

    keywords = extract_jd_keywords(jd, title)
    coverage = keyword_coverage(tex, keywords)
    if coverage.score >= min_score or not keywords:
        return [], coverage

    missing_preview = ", ".join(coverage.missing[:12])
    if len(coverage.missing) > 12:
        missing_preview += ", …"
    return [
        ValidationIssue(
            code="low_keyword_coverage",
            message=(
                f"Keyword coverage {coverage.score}% (min {min_score}%). "
                f"Missing: {missing_preview}"
            ),
        ),
    ], coverage

